object AppLogger {
    private const val MAX_LOG_CHUNK = 4000
    private const val DEFAULT_TAG = "AppLogger"

    fun init(debug: Boolean) {
        Timber.uprootAll()
        if (debug) {
            Timber.plant(ChunkingDebugTree())
        } else {
            Timber.plant(ChunkingReleaseTree())
        }
    }

    fun v(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        log(Log.VERBOSE, tag, message, throwable)
    }

    fun d(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        log(Log.DEBUG, tag, message, throwable)
    }

    fun i(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        log(Log.INFO, tag, message, throwable)
    }

    fun w(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        log(Log.WARN, tag, message, throwable)
    }

    fun e(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        log(Log.ERROR, tag, message, throwable)
    }

    fun logException(tag: String = DEFAULT_TAG, throwable: Throwable, context: String? = null) {
        val prefix = context?.let { "$it\n" } ?: ""
        log(Log.ERROR, tag, prefix + Log.getStackTraceString(throwable), throwable)
    }

    fun logAuthAttempt(
        username: String?,
        method: String,
        success: Boolean,
        reason: String? = null,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        val status = if (success) "SUCCESS" else "FAILED"
        val meta = metadata.entries.joinToString(", ") { "${it.key}=${it.value}" }
        val msg = buildString {
            append("AUTH_ATTEMPT status=").append(status)
            append(" method=").append(method)
            append(" username=").append(username ?: "null")
            if (!reason.isNullOrBlank()) append(" reason=").append(reason)
            if (meta.isNotBlank()) append(" metadata={").append(meta).append("}")
        }
        if (success) i("AuthLogger", msg) else w("AuthLogger", msg)
    }

    fun logDatabaseQuery(
        sql: String,
        parameters: List<Any?> = emptyList(),
        durationMs: Long? = null,
        rowsAffected: Int? = null
    ) {
        val msg = buildString {
            append("DB_QUERY sql=").append(sql)
            append(" params=").append(parameters.joinToString(prefix = "[", postfix = "]"))
            if (durationMs != null) append(" durationMs=").append(durationMs)
            if (rowsAffected != null) append(" rowsAffected=").append(rowsAffected)
        }
        v("DatabaseLogger", msg)
    }

    fun logDatabaseError(
        sql: String,
        parameters: List<Any?> = emptyList(),
        throwable: Throwable
    ) {
        val msg = "DB_QUERY_ERROR sql=$sql params=${parameters.joinToString(prefix = "[", postfix = "]")}"
        e("DatabaseLogger", msg, throwable)
        logException("DatabaseLogger", throwable, msg)
    }

    private fun log(priority: Int, tag: String, message: String, throwable: Throwable?) {
        val fullMessage = if (throwable != null && !message.contains(Log.getStackTraceString(throwable))) {
            "$message\n${Log.getStackTraceString(throwable)}"
        } else {
            message
        }

        when (priority) {
            Log.VERBOSE -> Timber.tag(tag).v(fullMessage)
            Log.DEBUG -> Timber.tag(tag).d(fullMessage)
            Log.INFO -> Timber.tag(tag).i(fullMessage)
            Log.WARN -> Timber.tag(tag).w(fullMessage)
            Log.ERROR -> Timber.tag(tag).e(fullMessage)
            else -> Timber.tag(tag).log(priority, fullMessage)
        }
    }

    private class ChunkingDebugTree : Timber.DebugTree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            chunkAndLog(priority, tag ?: DEFAULT_TAG, message, t)
        }
    }

    private class ChunkingReleaseTree : Timber.Tree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            chunkAndLog(priority, tag ?: DEFAULT_TAG, message, t)
        }
    }

    private fun chunkAndLog(priority: Int, tag: String, message: String, t: Throwable?) {
        if (message.length <= MAX_LOG_CHUNK) {
            Log.println(priority, tag, message)
            return
        }
        var i = 0
        val length = message.length
        while (i < length) {
            var newline = message.indexOf('\n', i).let { if (it == -1) length else it }
            do {
                val end = minOf(newline, i + MAX_LOG_CHUNK)
                Log.println(priority, tag, message.substring(i, end))
                i = end
            } while (i < newline)
            i++
        }
        if (t != null) {
            Log.println(priority, tag, Log.getStackTraceString(t))
        }
    }
}

class VerboseHttpLoggingInterceptor(
    private val logger: (String) -> Unit = { AppLogger.v("ApiLogger", it) }
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val requestStartNs = System.nanoTime()

        logRequest(request)

        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - requestStartNs)
            logResponse(response, tookMs)
            response
        } catch (e: Exception) {
            AppLogger.logException("ApiLogger", e, "HTTP FAILED ${request.method} ${request.url}")
            throw e
        }
    }

    private fun logRequest(request: okhttp3.Request) {
        val requestBody = request.body
        val bodyString = requestBody?.let { bodyToString(it) } ?: ""
        val headersString = headersToString(request.headers)

        val message = buildString {
            append("HTTP REQUEST\n")
            append("url=").append(request.url).append('\n')
            append("method=").append(request.method).append('\n')
            append("headers=\n").append(headersString)
            if (bodyString.isNotBlank()) {
                append('\n').append("body=\n").append(bodyString)
            }
        }
        logger(message)
    }

    private fun logResponse(response: Response, tookMs: Long) {
        val responseBody = response.body
        val sourceBodyString = responseBody?.let { peekBodySafely(it) }.orEmpty()
        val headersString = headersToString(response.headers)

        val message = buildString {
            append("HTTP RESPONSE\n")
            append("url=").append(response.request.url).append('\n')
            append("code=").append(response.code).append('\n')
            append("message=").append(response.message).append('\n')
            append("protocol=").append(response.protocol).append('\n')
            append("durationMs=").append(tookMs).append('\n')
            append("headers=\n").append(headersString)
            if (sourceBodyString.isNotBlank()) {
                append('\n').append("body=\n").append(sourceBodyString)
            }
        }
        logger(message)
    }

    private fun headersToString(headers: Headers): String {
        if (headers.size == 0) return "(none)"
        val builder = StringBuilder()
        for (i in 0 until headers.size) {
            builder.append(headers.name(i)).append(": ").append(headers.value(i)).append('\n')
        }
        return builder.toString().trimEnd()
    }

    private fun bodyToString(body: RequestBody): String {
        return try {
            val buffer = Buffer()
            body.writeTo(buffer)
            val charset = body.contentType().charsetOrUtf8()
            if (isPlaintext(buffer)) {
                buffer.readString(charset)
            } else {
                "(binary ${body.contentType()})"
            }
        } catch (e: Exception) {
            AppLogger.logException("ApiLogger", e, "Failed to read request body")
            "(unreadable body)"
        }
    }

    private fun peekBodySafely(body: ResponseBody): String {
        return try {
            val source = body.source()
            source.request(Long.MAX_VALUE)
            val buffer = source.buffer.clone()
            val charset = body.contentType().charsetOrUtf8()
            if (!isPlaintext(buffer)) {
                "(binary ${body.contentType()})"
            } else {
                buffer.readString(charset)
            }
        } catch (e: Exception) {
            AppLogger.logException("ApiLogger", e, "Failed to read response body")
            "(unreadable body)"
        }
    }

    private fun MediaType?.charsetOrUtf8(): Charset {
        return this?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
    }

    private fun isPlaintext(buffer: Buffer): Boolean {
        return try {
            val prefix = Buffer()
            val byteCount = minOf(buffer.size, 64)
            buffer.copyTo(prefix, 0, byteCount)
            for (i in 0 until 16) {
                if (prefix.exhausted()) break
                val codePoint = prefix.readUtf8CodePoint()
                if (Character.isISOControl(codePoint) && !Character.isWhitespace(codePoint)) {
                    return false
                }
            }
            true
        } catch (_: EOFException) {
            false
        }
    }
}

object LoggingOkHttpFactory {
    fun create(baseBuilder: OkHttpClient.Builder = OkHttpClient.Builder()): OkHttpClient {
        return baseBuilder
            .addInterceptor(VerboseHttpLoggingInterceptor())
            .build()
    }
}

object DatabaseQueryLogger {
    inline fun <T> logQuery(
        sql: String,
        parameters: List<Any?> = emptyList(),
        block: () -> T
    ): T {
        val start = System.nanoTime()
        return try {
            val result = block()
            val durationMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLogger.logDatabaseQuery(sql, parameters, durationMs)
            result
        } catch (t: Throwable) {
            AppLogger.logDatabaseError(sql, parameters, t)
            throw t
        }
    }
}

object AuthLogger {
    fun logSuccess(
        username: String?,
        method: String,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        AppLogger.logAuthAttempt(
            username = username,
            method = method,
            success = true,
            metadata = metadata
        )
    }

    fun logFailure(
        username: String?,
        method: String,
        reason: String,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        AppLogger.logAuthAttempt(
            username = username,
            method = method,
            success = false,
            reason = reason,
            metadata = metadata
        )
    }

    fun logException(
        username: String?,
        method: String,
        throwable: Throwable,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        AppLogger.logAuthAttempt(
            username = username,
            method = method,
            success = false,
            reason = throwable.message ?: throwable::class.java.simpleName,
            metadata = metadata
        )
        AppLogger.logException("AuthLogger", throwable, "AUTH_EXCEPTION username=$username method=$method")
    }
}

object CrashLogger {
    fun install() {
        val existingHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            AppLogger.logException(
                tag = "CrashLogger",
                throwable = throwable,
                context = "UNCAUGHT_EXCEPTION thread=${thread.name}"
            )
            existingHandler?.uncaughtException(thread, throwable)
        }
    }
}

